from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language phrase for a single predicate."""
        # Strip surrounding quotes and whitespace
        obj = obj.strip().strip('"')
        # Normalise predicate for lookup
        p = pred.lower().replace(" ", "")
        # Helper to format ISO dates nicely
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Mapping of predicates to phrase templates
        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            # Return adjective phrase for nationality to allow combination.
            low_obj = obj.lower()
            if "united states" in low_obj:
                return "an American"
            # Generic fallback: indicate origin.
            return f"from {obj}"
        if p == "senators" or p == "senator":
            # Subject is a place/state, object is a person.
            # Produce a natural phrasing for a senator.
            return f"{obj} is a senator in {subj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            # Return adjective/status phrase for combination.
            low = obj.lower()
            if low == "retired":
                return "retired"
            # Fallback: just return the status string in lowercase
            return low
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut
            return f"{subj} was a crew member of {obj}"
        if p == "timeinspace":
            # Convert minutes to hours/minutes if possible
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"{subj} spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"{subj} spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            # Subject is a mission/spacecraft
            # Prefer phrasing matching reference sentences
            return f"The {subj} was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj} is the state bird of {subj}"
        if p == "leader":
            return f"{obj} is the leader of {subj}"
        if p == "affiliation":
            return f"{subj} is affiliated with {obj}"
        if p == "competein":
            return f"{subj} competes in {obj}"
        if p == "president":
            return f"{obj} is the president of {subj}"
        if p == "gemstone":
            return f"{obj} is a gemstone found in {subj}"
        if p == "mascot":
            return f"{obj} is the mascot of {subj}"
        if p == "cosparid":
            return f"{subj} has COSPAR ID {obj}"
        if p == "utcoffset":
            return f"{subj} has a UTC offset of {obj}"
        if p == "part":
            return f"{subj} is part of {obj}"
        if p == "ispartof":
            return f"{subj} is part of {obj}"
        if p == "higher":
            return f"{subj} is higher than {obj}"
        if p == "fossil":
            return f"{obj} is a fossil from {subj}"
        if p == "partsType".lower():
            return f"{subj}'s parts type is {obj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        adj_parts = []
        other_parts = []
        for t in items:
            p_key = t.predicate.lower().replace(" ", "")
            if p_key in ("nationality", "status"):
                adj = phrase(subj, t.predicate, t.object)
                if adj:
                    adj_parts.append(adj)
            else:
                other_parts.append(phrase(subj, t.predicate, t.object))

        # Build sentence for this subject
        if adj_parts:
            # Combine adjectives with "and"
            adj_str = " and ".join(adj_parts)
            base = f"{subj} is {adj_str}"
            if other_parts:
                if len(other_parts) == 1:
                    sent = f"{base}, {other_parts[0]}"
                else:
                    sent = f"{base}, " + ", ".join(other_parts[:-1]) + ", and " + other_parts[-1]
            else:
                sent = base
        else:
            if len(other_parts) == 1:
                sent = other_parts[0]
            else:
                sent = ", ".join(other_parts[:-1]) + ", and " + other_parts[-1]

        sentences.append(sent)

    # Combine subject sentences and ensure final punctuation
    return " ".join(sentences).strip() + "."

